insert into public.jobs (title, company, location, trade, employment_type, salary_min, salary_max, salary_period, description, requirements, benefits, apply_url, apply_email, is_approved, posted_at) values
  ('CNC Programmer / Operator', 'Heartwood Cabinetry', 'Grand Rapids, MI', 'cnc-machining', 'full-time', 62000, 85000, 'year', 'Program and run our 5x12 Biesse Rover B FT and Thermwood M45. Generate nests in Alphacam, run toolpath verification, manage spoilboard maintenance, and work with the shop floor on optimizing cycle times.', 'Minimum 3 years CNC programming experience, Alphacam or equivalent CAM software, comfortable reading shop drawings and cut lists, able to lift 50 lbs.', 'Full medical/dental/vision, 401k with 4% match, 2 weeks PTO to start, paid holidays, boot and tool allowance.', null, 'careers@heartwoodcabinetry.com', true, now() - interval '2 days'),
  ('Architectural Millwork Estimator', 'Meridian Millwork', 'Dallas, TX', 'business-estimating', 'full-time', 78000, 110000, 'year', 'Perform takeoffs on commercial bid packages, build estimates in Microvellum, coordinate with PMs on scope, pricing, and schedule. Typical projects $250k–$4M.', '5+ years estimating commercial architectural millwork, Microvellum or Innergy experience, strong Excel, ability to read full construction documents.', 'Medical, dental, vision, 3 weeks PTO, 401k match, remote 1 day/week after 90 days.', 'https://meridianmillwork.com/careers', null, true, now() - interval '4 days'),
  ('Journeyman Cabinetmaker', 'Cascadia Cabinet Co.', 'Portland, OR', 'cabinet-making', 'full-time', 30, 42, 'hour', 'High-end residential cabinet shop looking for an experienced bench hand who can move between machining, assembly, and shop installs. Frameless European construction, solid wood doors and drawers, occasional on-site finishing.', 'Journeyman-level — can run a panel saw, edgebander, line borer, and assemble a kitchen front to back. Finish carpentry experience a plus.', 'Top-of-market hourly, health care stipend, simple IRA match, 10 paid holidays, flexible scheduling.', null, 'hiring@cascadiacabinet.com', true, now() - interval '1 day'),
  ('Shop Foreman', 'Summit Architectural Woodwork', 'Denver, CO', 'shop-management', 'full-time', 85000, 120000, 'year', 'Run the floor of a 12-person architectural millwork shop. Scheduling, QC, mentoring, machine maintenance planning, production reporting to ownership.', '10+ years in architectural millwork, 3+ years in a lead or foreman role, AWI QCP familiarity, calm under pressure.', 'Full benefits, 4 weeks PTO, annual bonus tied to shop margin, truck allowance.', 'https://summitaw.com/jobs', null, true, now() - interval '6 days'),
  ('Spray Finisher', 'Ironwood Custom', 'Nashville, TN', 'finishing-coatings', 'full-time', 25, 34, 'hour', 'Conversion varnish and waterborne finishing on cabinet and furniture grade work. Work in a temperature-controlled booth with downdraft flow, flash-off area, and forced-air drying.', '3+ years professional spray experience, pigmented CV and clear finishes, able to tint to sample, Kremlin AAA familiarity a plus.', 'Medical/dental, paid vacation, respirator program and PPE provided, quarterly bonuses.', null, 'work@ironwoodcustom.com', true, now() - interval '3 days'),
  ('Project Manager — Commercial Casework', 'Keystone Casework', 'Harrisburg, PA', 'business-estimating', 'full-time', 82000, 115000, 'year', 'Own 4–6 active commercial casework projects in healthcare, education, and corporate sectors. Submittals, RFIs, shop drawings coordination, installation scheduling.', 'Minimum 5 years PM experience in architectural millwork or GC environment, AutoCAD/Revit literacy, strong schedule and budget ownership.', 'Health insurance, dental, vision, 401k, 3 weeks PTO, vehicle allowance.', 'https://keystonecasework.com/careers', null, true, now() - interval '5 days'),
  ('Cabinet Installer', 'Maple Ridge Cabinetry', 'Burlington, VT', 'cabinet-making', 'full-time', 28, 38, 'hour', 'Residential kitchen and built-in installs across VT, NH, and northern MA. Drive a shop-supplied truck, lead a 2-person crew, handle scribing and site finish touch-ups.', '5+ years installing custom cabinets, clean driving record, own hand tools, ability to problem-solve on-site.', 'Per diem for overnight jobs, truck + fuel provided, paid vacation, health insurance stipend.', null, 'jobs@mapleridgecab.com', true, now() - interval '7 days'),
  ('Entry-Level Cabinetmaker / Apprentice', 'Copper State Millwork', 'Phoenix, AZ', 'cabinet-making', 'apprenticeship', 18, 24, 'hour', 'Structured 3-year apprenticeship program. Rotate through machining, assembly, finishing, and installation. Paid classroom hours and mentoring with a journeyman lead.', 'No experience required. Reliable, curious, willing to learn. High school diploma or GED.', 'Paid training, structured raises, tool program, medical, 401k after 1 year.', 'https://copperstatemillwork.com/apprenticeship', null, true, now() - interval '10 days'),
  ('Wood Finisher — Lead', 'Pacific Crest Cabinets', 'Seattle, WA', 'finishing-coatings', 'full-time', 75000, 95000, 'year', 'Lead a 3-person finishing department on high-end residential work. Own the schedule, QC, color development, and finish specifications for every project.', '7+ years professional finishing, 2+ in a lead role, comfortable developing custom stain and color formulas, strong on safety and ventilation.', 'Full benefits, 3 weeks PTO, respirator fit testing and medical, profit sharing.', null, 'hire@pacificcrestcab.com', true, now() - interval '2 days'),
  ('Sales & Design Consultant — Kitchen & Bath', 'Hudson Valley Woodworks', 'Kingston, NY', 'business-estimating', 'full-time', 55000, 110000, 'year', 'Client-facing role: consult with homeowners and designers, develop designs in 2020 Design, produce quotes and contracts, manage project through to installation.', '3+ years in kitchen/bath design sales, 2020 or KCD experience, portfolio of completed projects, great communication.', 'Base + commission, health insurance, paid vacation, design allowance.', 'https://hudsonvalleyww.com/careers', null, true, now() - interval '8 days'),
  ('Edgebander Operator', 'Riverbend Millwork', 'Cincinnati, OH', 'cnc-machining', 'full-time', 22, 30, 'hour', 'Run our Homag Ambition 1440 and SCM Olimpic K 360. Setup for PVC, ABS, wood veneer, and solid-wood edging. Daily cleaning and glue-pot maintenance.', '2+ years edgebander experience, comfortable with tape, coil, and solid-wood edges, basic mechanical aptitude for setup changes.', 'Medical/dental, 401k, paid vacation, overtime available.', null, 'careers@riverbendmw.com', true, now() - interval '4 days'),
  ('CAD Drafter / Engineered Drawings', 'Stonewall Custom Cabinetry', 'Charlotte, NC', 'business-estimating', 'full-time', 58000, 78000, 'year', 'Produce shop drawings, cut lists, and installation drawings in Cabinet Vision. Coordinate with PMs and the CNC programmer on engineered files.', '3+ years producing cabinet shop drawings, Cabinet Vision proficient, familiarity with dowel and LockDowel construction methods.', 'Medical, dental, 401k match, 2 weeks PTO, hybrid after probation.', 'https://stonewallcab.com/jobs', null, true, now() - interval '3 days'),
  ('Plant Manager', 'Great Lakes Architectural', 'Chicago, IL', 'shop-management', 'full-time', 125000, 165000, 'year', 'Own production of a 45,000 sq ft architectural millwork plant. ~30 FTE. Responsible for throughput, quality, safety, and continuous improvement.', '10+ years in millwork production leadership, AWI familiarity, lean manufacturing background, strong P&L ownership.', 'Executive benefits package, bonus, equity opportunity, relocation assistance.', null, 'execsearch@greatlakesam.com', true, now() - interval '12 days'),
  ('Custom Door & Drawer Maker', 'Sierra Fine Cabinetry', 'Reno, NV', 'cabinet-making', 'full-time', 26, 36, 'hour', 'Dedicated door and drawer cell — 5-piece, MDF, slab, shaker, glass doors. Run a dedicated shaper, coping sled, and drawer box rig.', '3+ years making cabinet doors and drawers, able to set up cope-and-stick tooling, strong attention to repeatable quality.', 'Medical, dental, paid time off, shop-sponsored training, overtime available.', null, 'jobs@sierrafinecab.com', true, now() - interval '5 days'),
  ('Architectural Millwork Installer', 'Granite State Millwork', 'Manchester, NH', 'cabinet-making', 'full-time', 30, 45, 'hour', 'Commercial install crews — healthcare, courtrooms, corporate. Paneling, reception desks, high-end casework. Travel across New England.', 'Minimum 5 years commercial millwork install, foreman-level ability preferred, clean driving record, OSHA 10 minimum.', 'Per diem, travel pay, truck provided, full benefits, 401k match.', 'https://graniteaw.com/careers', null, true, now() - interval '6 days'),
  ('Shop Apprentice — Night Shift', 'Bayside Cabinet Works', 'Tampa, FL', 'cabinet-making', 'part-time', 17, 22, 'hour', 'Night-shift assembly and prep work. Great entry-level role for someone looking to learn the trade while working another job or going to school.', 'Dependable, teachable, able to work 5pm–1am Mon–Thu, ok being on your feet all shift.', 'Shift differential, paid training, uniforms provided, meals on long shifts.', null, 'work@baysidecab.com', true, now() - interval '1 day'),
  ('Finishing Shop Lead', 'Tall Timber Custom', 'Boise, ID', 'finishing-coatings', 'full-time', 72000, 92000, 'year', 'Run a 2-booth finishing department specializing in high-end furniture and architectural millwork. Color matching, finish engineering, QC, and PPE program ownership.', '5+ years finishing, 2+ in a lead role, strong on lacquer and waterborne systems, able to interpret architect finish specs.', 'Top-of-market pay, medical, dental, respirator program, tool allowance.', null, 'careers@talltimbercustom.com', true, now() - interval '8 days'),
  ('IT / Shop Systems Administrator', 'Foundry Millwork', 'Pittsburgh, PA', 'shop-management', 'full-time', 78000, 105000, 'year', 'Own our shop-floor IT: CNC network, file server, estimating/ERP system, barcode stations, and design software deployment. Hybrid role — 3 days on-site.', 'IT infrastructure background, familiarity with Cabinet Vision or Microvellum a strong plus, comfortable around machinery.', 'Medical, dental, vision, 401k match, 3 weeks PTO, hybrid schedule.', 'https://foundrymillwork.com/jobs', null, true, now() - interval '15 days'),
  ('Carving & CNC Artist', 'Cardinal Cabinetry', 'St. Louis, MO', 'cnc-machining', 'contract', 35, 55, 'hour', 'Project-based contract: carve ornamental elements for a hospitality build (corbels, capitals, medallions). Initial run ~120 pieces over 10 weeks.', 'Proven CNC 3D carving portfolio, Aspire or ArtCAM experience, supply own model files, comfortable with select hardwoods.', 'Contract rate, flexible schedule, shop time available for setup and finishing if needed.', null, 'procurement@cardinalcab.com', true, now() - interval '9 days'),
  ('Wood Shop Teacher — Evening Adult Program', 'Appalachian Architectural Woodwork', 'Asheville, NC', 'cabinet-making', 'part-time', 32, 45, 'hour', 'Teach a 12-week evening adult-education woodworking program through our community shop. Two nights/week, project-based curriculum.', 'Professional woodworking background, teaching or mentoring experience preferred, able to design a progressive curriculum.', 'Flexible hours, stipend per cohort, full access to the shop outside class, travel reimbursement for local students.', 'https://appalachianaw.com/education', null, true, now() - interval '20 days');
