-- ============================================================
-- Millwork.io SAMPLE DATA — 20 records per major table
-- Run AFTER schema.sql and seed.sql. Safe to re-run (idempotent).
-- All author_id / seller_id / claimed_by left NULL (profiles FK
-- to auth.users, so real users must post/own content).
-- ============================================================

-- ------------------------------------------------------------
-- SUPPLIERS (extends the 4 in seed.sql to 20)
-- ------------------------------------------------------------
on conflict (slug) do update set name = excluded.name, category = excluded.category, trade = excluded.trade, logo_initials = excluded.logo_initials, description = excluded.description, website = excluded.website, phone = excluded.phone, email = excluded.email, address = excluded.address, rating = excluded.rating, review_count = excluded.review_count, badges = excluded.badges;


-- ------------------------------------------------------------
-- FORUM THREADS (20 threads across categories)
-- author_id left NULL — anonymous seed content
-- IMPORTANT: reply_count is NOT seeded. It starts at 0 and is
-- maintained by the bump_thread_on_post trigger as real posts
-- are inserted (see seed-users-and-posts.sql). Previously we
-- seeded fake counts (47, 62, 127) that never matched the actual
-- forum_posts rows, so threads displayed inflated numbers.
-- ------------------------------------------------------------
on conflict (slug) do update set title = excluded.title, category_id = excluded.category_id, is_pinned = excluded.is_pinned, is_solved = excluded.is_solved, view_count = excluded.view_count, last_reply_at = excluded.last_reply_at;


-- ------------------------------------------------------------
-- JOBS (20 openings)
-- ------------------------------------------------------------
-- Use content-hash-style slug in title to dedupe via (title, company) — but the table has no slug.
-- We dedupe by (title, company) using a unique-ish where clause pattern.
-- Simpler: delete prior seed rows by company label, then re-insert.
delete from public.jobs where company in (
  'Heartwood Cabinetry','Meridian Millwork','Cascadia Cabinet Co.','Summit Architectural Woodwork',
  'Ironwood Custom','Keystone Casework','Maple Ridge Cabinetry','Copper State Millwork',
  'Pacific Crest Cabinets','Hudson Valley Woodworks','Riverbend Millwork','Stonewall Custom Cabinetry',
  'Great Lakes Architectural','Sierra Fine Cabinetry','Granite State Millwork','Bayside Cabinet Works',
  'Tall Timber Custom','Foundry Millwork','Cardinal Cabinetry','Appalachian Architectural Woodwork'
);



-- ------------------------------------------------------------
-- EVENTS (20)
-- ------------------------------------------------------------
on conflict (slug) do update set title = excluded.title, description = excluded.description, event_type = excluded.event_type, start_date = excluded.start_date, end_date = excluded.end_date, location = excluded.location, venue_name = excluded.venue_name, is_online = excluded.is_online, registration_url = excluded.registration_url, trade = excluded.trade;


-- ------------------------------------------------------------
-- WIKI ARTICLES (20)
-- ------------------------------------------------------------
on conflict (slug) do update set title = excluded.title, category = excluded.category, trade = excluded.trade, excerpt = excluded.excerpt, body = excluded.body, read_time_minutes = excluded.read_time_minutes, is_published = excluded.is_published, published_at = excluded.published_at;


-- ------------------------------------------------------------
-- NEWS ARTICLES (20)
-- ------------------------------------------------------------
on conflict (slug) do update set title = excluded.title, category = excluded.category, trade = excluded.trade, excerpt = excluded.excerpt, body = excluded.body, source_url = excluded.source_url, is_published = excluded.is_published, published_at = excluded.published_at;


-- ------------------------------------------------------------
-- MARKETPLACE LISTINGS (20)
-- ------------------------------------------------------------
on conflict (slug) do update set title = excluded.title, category = excluded.category, trade = excluded.trade, condition = excluded.condition, price = excluded.price, description = excluded.description, location = excluded.location, is_approved = excluded.is_approved, is_sold = excluded.is_sold;

-- ============================================================
-- Summary:
--   Suppliers: 20 total (4 from seed.sql + 16 here)
--   Forum threads: 20
--   Jobs: 20
--   Events: 20
--   Wiki articles: 20
--   News articles: 20
--   Marketplace listings: 20
-- All author_id/seller_id/claimed_by are NULL. After you create your
-- own profile, you can claim content with:
--   update public.suppliers set claimed_by = auth.uid() where slug = '...';
-- ============================================================
